class Solution {
    vector<vector<int>> res;
    vector<int> path;
    void dfs(vector<int>& a, int i) {
        if (i==(int)a.size()) { res.push_back(path); return; }
        dfs(a,i+1);
        path.push_back(a[i]); dfs(a,i+1); path.pop_back();
    }
public:
    vector<vector<int>> subsets(vector<int>& nums) {
        dfs(nums,0); return res;
    }
};
